from pathlib import Path

path = Path('lib/main.dart')
text = path.read_text(encoding='utf-8')

if 'Путь к результату' in text:
    print('already applied')
    raise SystemExit(0)

def replace_between(start_marker: str, end_marker: str, new_block: str) -> None:
    global text
    start = text.index(start_marker)
    end = text.index(end_marker, start)
    text = text[:start] + new_block.rstrip() + '\n\n' + text[end:]

replace_between('class GoalHero extends StatelessWidget {', 'class EmptyAction extends StatelessWidget {', "class GoalHero extends StatelessWidget {\n  const GoalHero({required this.app, super.key});\n  final AppState app;\n\n  @override\n  Widget build(BuildContext context) {\n    final g = app.goal!;\n    final total = app.goalDone + app.goalActive;\n    final progress = total == 0 ? 0.0 : app.goalDone / total;\n\n    return Container(\n      padding: const EdgeInsets.all(22),\n      decoration: BoxDecoration(\n        gradient: const LinearGradient(\n          colors: [Color(0xFF102E2A), Color(0xFF356A61)],\n          begin: Alignment.topLeft,\n          end: Alignment.bottomRight,\n        ),\n        borderRadius: BorderRadius.circular(29),\n        boxShadow: const [\n          BoxShadow(\n            color: Color(0x24132D2A),\n            blurRadius: 24,\n            offset: Offset(0, 13),\n          ),\n        ],\n      ),\n      child: Column(\n        crossAxisAlignment: CrossAxisAlignment.start,\n        children: [\n          Row(\n            children: [\n              Container(\n                padding:\n                    const EdgeInsets.symmetric(horizontal: 10, vertical: 6),\n                decoration: BoxDecoration(\n                  color: Colors.white12,\n                  borderRadius: BorderRadius.circular(20),\n                ),\n                child: const Text(\n                  'ГЛАВНАЯ ЦЕЛЬ',\n                  style: TextStyle(\n                    color: mint,\n                    fontSize: 11,\n                    fontWeight: FontWeight.w900,\n                    letterSpacing: 1.1,\n                  ),\n                ),\n              ),\n              const Spacer(),\n              const Icon(Icons.north_east_rounded, color: Colors.white54),\n            ],\n          ),\n          const SizedBox(height: 15),\n          Text(\n            g.title,\n            style: const TextStyle(\n              color: Colors.white,\n              fontSize: 25,\n              height: 1.14,\n              fontWeight: FontWeight.w900,\n            ),\n          ),\n          if (g.result.isNotEmpty) ...[\n            const SizedBox(height: 8),\n            Text(\n              g.result,\n              style: const TextStyle(\n                color: Color(0xFFD4E0DD),\n                height: 1.35,\n              ),\n            ),\n          ],\n          const SizedBox(height: 18),\n          ClipRRect(\n            borderRadius: BorderRadius.circular(9),\n            child: LinearProgressIndicator(\n              value: progress,\n              minHeight: 7,\n              backgroundColor: Colors.white12,\n              valueColor: const AlwaysStoppedAnimation(mint),\n            ),\n          ),\n          const SizedBox(height: 14),\n          Row(\n            children: [\n              _metric('${app.goalDone}', 'завершено'),\n              const SizedBox(width: 9),\n              _metric('${app.goalActive}', 'в работе'),\n              const SizedBox(width: 9),\n              _metric('${g.areas.length}', 'этапов'),\n            ],\n          ),\n        ],\n      ),\n    );\n  }\n\n  Widget _metric(String value, String label) => Expanded(\n    child: Container(\n      padding: const EdgeInsets.symmetric(vertical: 11, horizontal: 5),\n      decoration: BoxDecoration(\n        color: Colors.white10,\n        borderRadius: BorderRadius.circular(15),\n      ),\n      child: Column(\n        children: [\n          Text(\n            value,\n            style: const TextStyle(\n              color: Colors.white,\n              fontSize: 17,\n              fontWeight: FontWeight.w900,\n            ),\n          ),\n          Text(\n            label,\n            textAlign: TextAlign.center,\n            style: const TextStyle(color: Colors.white60, fontSize: 11),\n          ),\n        ],\n      ),\n    ),\n  );\n}")

replace_between('class GoalScreen extends StatelessWidget {', 'class GoalEditor extends StatefulWidget {', "class GoalScreen extends StatelessWidget {\n  const GoalScreen({required this.app, super.key});\n  final AppState app;\n\n  @override\n  Widget build(BuildContext context) {\n    final active =\n        app.actions.where((item) => item.goal && item.state == null).toList();\n    final recent = app.history.where((item) => item.goal).take(5).toList();\n\n    return Scaffold(\n      appBar: AppBar(title: const Text('Моя цель')),\n      body: ListView(\n        padding: const EdgeInsets.fromLTRB(18, 4, 18, 90),\n        children: [\n          if (app.goal == null)\n            CreateGoal(app: app)\n          else ...[\n            Text(\n              'Путь к результату',\n              style: Theme.of(context).textTheme.headlineMedium,\n            ),\n            const SizedBox(height: 6),\n            const Text(\n              'Добавляйте действия по мере движения. Не обязательно планировать весь путь заранее.',\n            ),\n            const SizedBox(height: 18),\n            GoalHero(app: app),\n            const SizedBox(height: 22),\n            Row(\n              children: [\n                const Expanded(\n                  child: Text(\n                    'Следующие действия',\n                    style: TextStyle(\n                      fontSize: 20,\n                      fontWeight: FontWeight.w900,\n                    ),\n                  ),\n                ),\n                Text(\n                  '${active.length} в работе',\n                  style: const TextStyle(\n                    color: green,\n                    fontWeight: FontWeight.w800,\n                  ),\n                ),\n              ],\n            ),\n            const SizedBox(height: 10),\n            if (active.isEmpty)\n              EmptyAction(\n                onTap: () => Navigator.push(\n                  context,\n                  MaterialPageRoute(\n                    builder: (_) => ActionEditor(app: app, goalDefault: true),\n                  ),\n                ),\n              )\n            else\n              ...active.map(\n                (item) => Padding(\n                  padding: const EdgeInsets.only(bottom: 9),\n                  child: ActionCard(app: app, item: item),\n                ),\n              ),\n            if (app.goal!.areas.isNotEmpty) ...[\n              const SizedBox(height: 18),\n              const Text(\n                'Этапы цели',\n                style: TextStyle(fontSize: 20, fontWeight: FontWeight.w900),\n              ),\n              const SizedBox(height: 9),\n              Card(\n                child: Padding(\n                  padding: const EdgeInsets.all(17),\n                  child: Wrap(\n                    spacing: 8,\n                    runSpacing: 8,\n                    children: app.goal!.areas\n                        .map(\n                          (area) => Container(\n                            padding: const EdgeInsets.symmetric(\n                              horizontal: 12,\n                              vertical: 9,\n                            ),\n                            decoration: BoxDecoration(\n                              color: const Color(0xFFEAF3EF),\n                              borderRadius: BorderRadius.circular(16),\n                            ),\n                            child: Text(\n                              area,\n                              style:\n                                  const TextStyle(fontWeight: FontWeight.w800),\n                            ),\n                          ),\n                        )\n                        .toList(),\n                  ),\n                ),\n              ),\n            ],\n            if (recent.isNotEmpty) ...[\n              const SizedBox(height: 18),\n              const Text(\n                'Недавнее движение',\n                style: TextStyle(fontSize: 20, fontWeight: FontWeight.w900),\n              ),\n              const SizedBox(height: 9),\n              Card(\n                child: Column(\n                  children: recent\n                      .map(\n                        (entry) => ListTile(\n                          leading: Icon(resultIcon(entry.state), color: green),\n                          title: Text(entry.title),\n                          subtitle: Text(\n                            '${resultName(entry.state)} · ${shortDate(entry.date)}',\n                          ),\n                        ),\n                      )\n                      .toList(),\n                ),\n              ),\n            ],\n            const SizedBox(height: 18),\n            FilledButton.icon(\n              onPressed: () => Navigator.push(\n                context,\n                MaterialPageRoute(\n                  builder: (_) => ActionEditor(app: app, goalDefault: true),\n                ),\n              ),\n              icon: const Icon(Icons.add_task),\n              label: const Text('Добавить следующее действие'),\n            ),\n            const SizedBox(height: 10),\n            OutlinedButton.icon(\n              onPressed: () => Navigator.push(\n                context,\n                MaterialPageRoute(\n                  builder: (_) => GoalEditor(app: app, existing: app.goal),\n                ),\n              ),\n              icon: const Icon(Icons.edit_outlined),\n              label: const Text('Изменить цель'),\n            ),\n          ],\n        ],\n      ),\n    );\n  }\n}")

path.write_text(text, encoding='utf-8')
print('applied')
